using Microsoft.AspNetCore.Mvc;
using Microsoft.Extensions.ML;
using Microsoft.ML;
using TicketClassifier.Models;

namespace TicketClassifier.Controllers;

[ApiController]
[Route("api/[controller]")]
public class TicketsController : ControllerBase
{
    private readonly PredictionEnginePool<TicketData, TicketPrediction> _pool;
    private readonly string[] _labels;

    public TicketsController(
        PredictionEnginePool<TicketData, TicketPrediction> pool,
        IWebHostEnvironment env)
    {
        _pool = pool;

        // Read label names from the saved model's schema so ordering is always correct
        var mlContext = new MLContext();
        var modelPath = Path.Combine(env.ContentRootPath, "Data", "model.zip");
        var model = mlContext.Model.Load(modelPath, out _);
        var outputSchema = model.GetOutputSchema(SchemaDefinition.Create(typeof(TicketData)));
        var labelColumn = outputSchema["PredictedLabel"];
        var slotNames = new VBuffer<ReadOnlyMemory<char>>();
        labelColumn.GetKeyValues(ref slotNames);
        _labels = slotNames.DenseValues().Select(v => v.ToString()).ToArray();
    }

    [HttpPost("classify")]
    public ActionResult<TicketResponse> Classify([FromBody] TicketRequest request)
    {
        var input = new TicketData
        {
            Subject = request.Subject,
            Description = request.Description,
            Priority = request.Priority
        };

        var prediction = _pool.Predict(input);

        var confidence = new Dictionary<string, float>();
        for (int i = 0; i < _labels.Length && i < prediction.Score.Length; i++)
        {
            confidence[_labels[i]] = prediction.Score[i];
        }

        return Ok(new TicketResponse
        {
            PredictedCategory = prediction.Category,
            Confidence = confidence
        });
    }
}

